n 15\",\n                            \"signal\": \"6Q\",\n                            \"path\": \"ROM Pin 3 (A7)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 16\",\n                            \"signal\": \"7Q\",\n                            \"path\": \"ROM Pin 5 (A5)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 17\",\n                            \"signal\": \"7D\",\n                            \"path\": \"RM3 Pin 7 -> ROM Pin 17 (I/O5) -> 66K Pin 6 (AD5)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 18\",\n                            \"signal\": \"8D\",\n                            \"path\": \"RM3 Pin 6 -> ROM Pin 16 (I/O4) -> 66K Pin 5 (AD4)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 19\",\n                            \"signal\": \"8Q\",\n                            \"path\": \"ROM Pin 6 (A4)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 20\",\n                            \"signal\": \"VCC\",\n                            \"path\": \"ROM Pin 28 (VCC) -> ROM Pin 1 (/WE)\",\n                            \"note\": \"\"\n                        }\n                    ]\n                },\n                {\n                    \"label\": \"ROM socket\",\n                    \"rows\": [\n                        {\n                            \"pin\": \"Pin 1\",\n                            \"signal\": \"VCC\",\n                            \"path\": \"ROM Pin 28 (VCC) -> 373 Pin 20 (VCC)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 2\",\n                            \"signal\": \"A12\",\n                            \"path\": \"66K Pin 13 (A12)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 3\",\n                            \"signal\": \"A7\",\n                            \"path\": \"373 Pin 15 (6Q)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 4\",\n                            \"signal\": \"A6\",\n                            \"path\": \"373 Pin 12 (5Q)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 5\",\n                            \"signal\": \"A5\",\n                            \"path\": \"373 Pin 16 (7Q)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 6\",\n                            \"signal\": \"A4\",\n                            \"path\": \"373 Pin 19 (8Q)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 7\",\n                            \"signal\": \"A3\",\n                            \"path\": \"373 Pin 9 (4Q)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 8\",\n                            \"signal\": \"A2\",\n                            \"path\": \"373 Pin 6 (3Q)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 9\",\n                            \"signal\": \"A1\",\n                            \"path\": \"373 Pin 5 (2Q)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 10\",\n                            \"signal\": \"A0\",\n                            \"path\": \"373 Pin 2 (1Q)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 11\",\n                            \"signal\": \"I/O0\",\n                            \"path\": \"RM3 Pin 2 -> 373 Pin 3 (1D) -> 66K Pin 1 (AD0)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 12\",\n                            \"signal\": \"I/O1\",\n                            \"path\": \"RM3 Pin 3 -> 373 Pin 4 (2D) -> 66K Pin 2 (AD1)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 13\",\n                            \"signal\": \"I/O2\",\n                            \"path\": \"RM3 Pin 4 -> 373 Pin 7 (3D) -> 66K Pin 3 (AD2)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 14\",\n                            \"signal\": \"GND\",\n                            \"path\": \"373 Pin 10 (GND) -> 373 Pin 1 (/OE)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 15\",\n                            \"signal\": \"I/O3\",\n                            \"path\": \"RM3 Pin 5 -> 373 Pin 8 (4D) -> 66K Pin 4 (AD3)\",\n                            \"note\": \"\"\n                        },\n                        {\n                            \"pin\": \"Pin 16\",\n                            \"signal\": \"I/O4\",\n                            \"path\": \"RM3 Pin 6 -> 373 Pin 18 (8D) -> 66K Pin 5 (AD4)\",\n                            \"note\": 